#!/usr/bin/env python3

import sys

def main():
    try:
        import sklearn_pro_max
    except ImportError:
        sys.stderr.write("The 'sklearn-pro-max' package is required. Install with: pip install sklearn-pro-max\n")
        sys.exit(1)

    # Train a model using sklearn_pro_max
    model = sklearn_pro_max.train_auto_model()

    # Attempt to persist the trained model
    try:
        import pickle
        with open("trained_model.pkl", "wb") as f:
            pickle.dump(model, f)
        print("Training complete. Model saved to trained_model.pkl")
    except Exception as e:
        print("Training complete, but the model could not be serialized with pickle.")
        print(f"Model repr: {repr(model)}")
        print(f"Serialization error: {e}")

if __name__ == "__main__":
    main()
